### Lazy Loading

`React.lazy` lets you defer loading a component until it is first rendered. Combined with Suspense, it reduces the initial bundle size and improves performance.

---

### Basic Usage

```jsx
import { lazy, Suspense } from 'react';

const HeavyChart = lazy(() => import('./HeavyChart'));

function Dashboard() {
  const [showChart, setShowChart] = useState(false);

  return (
    <div>
      <button onClick={() => setShowChart(true)}>Show Chart</button>
      <Suspense fallback={<div>Loading chart...</div>}>
        {showChart && <HeavyChart />}
      </Suspense>
    </div>
  );
}
```

### Named Exports

```jsx
const { MyComponent } = lazy(() =>
  import('./MyModule').then(module => ({ default: module.MyComponent }))
);
```

### Route-Based Lazy Loading

```jsx
import { lazy, Suspense } from 'react';
import { Routes, Route } from 'react-router-dom';

const Home = lazy(() => import('./pages/Home'));
const About = lazy(() => import('./pages/About'));
const Dashboard = lazy(() => import('./pages/Dashboard'));

function App() {
  return (
    <Suspense fallback={<PageLoader />}>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/dashboard" element={<Dashboard />} />
      </Routes>
    </Suspense>
  );
}
```

| Strategy | Use Case |
|----------|----------|
| Route-level | Each page loads on demand |
| Component-level | Heavy components (charts, editors) |
| Conditional | Components shown only on user action |

> **Key Point:** Lazy loading improves initial load time but adds a brief loading state when the lazy component renders. Use it for routes and heavy components not needed on the first screen (below the fold).

codeExample:
import { lazy, Suspense, useState } from 'react';

const MarkdownEditor = lazy(() => import('./MarkdownEditor'));
const ImageGallery = lazy(() => import('./ImageGallery'));

function PostCreator() {
  const [mode, setMode] = useState('text');

  return (
    <div>
      <button onClick={() => setMode('text')}>Text</button>
      <button onClick={() => setMode('gallery')}>Gallery</button>
      <Suspense fallback={<Spinner />}>
        {mode === 'text' ? <MarkdownEditor /> : <ImageGallery />}
      </Suspense>
    </div>
  );
}
